{
    global:
        # Python module entry point(s).
        PyInit_*;

        # Expose the full zvec C++ namespace. All algorithm libraries
        # (including DiskAnn) are statically linked via --whole-archive and
        # share the same Factory singletons. Exporting zvec::* ensures
        # correct symbol resolution across all whole-archived static libs.
        extern "C++" {
            "zvec::*";
            zvec::*;
            # Also export the compiler-generated helper symbols that live
            # alongside symbols in the zvec namespace (guard variables for
            # static locals, vtables, typeinfo, VTT, construction vtables,
            # thunks). These ensure a single copy of each singleton guard
            # variable across all whole-archived static libraries.
            "guard variable for zvec::*";
            "vtable for zvec::*";
            "VTT for zvec::*";
            "typeinfo for zvec::*";
            "typeinfo name for zvec::*";
            "construction vtable for zvec::*";
            "non-virtual thunk to zvec::*";
            "virtual thunk to zvec::*";
        };
    local:
        *;
};
